// shared/localization.js - Single source of truth for UI string localization.
// Content script version is generated by scripts/build-dataclasses.js -> content-components/localization.js
//
// Localization is keyed off document.documentElement.lang (the language claude.ai sets on its
// page), normalized to one of SUPPORTED_LOCALES. English is the base and fallback.
//
// Supported locales mirror claude.ai's own UI language set. The two Spanish variants
// (es-419 / es-ES) collapse to a single "es" table (drafts; differences don't surface in
// short UI labels). Portuguese is pt-BR only.
//
// NOTE: nothing in this module touches the DOM or storage at import time. t()/detectLocale()/
// fmtNum() read document.documentElement.lang lazily, per call, so they are safe to *define*
// in a DOM-less context (e.g. the background service worker) as long as they are not *called*
// there.

export const SUPPORTED_LOCALES = ['en', 'fr', 'de', 'hi', 'id', 'it', 'ja', 'ko', 'pt-BR', 'es'];

