// Normalize a raw lang string (e.g. document.documentElement.lang, or a stored lastLang)
// to one of SUPPORTED_LOCALES. Falls back to 'en'.
export function normalizeLocale(raw) {
	if (!raw) return 'en';
	const lc = String(raw).toLowerCase().trim();
	if (!lc) return 'en';

	// Exact (case-insensitive) match against supported codes (e.g. 'pt-br' -> 'pt-BR').
	const exact = SUPPORTED_LOCALES.find(l => l.toLowerCase() === lc);
	if (exact) return exact;

	// Base-language handling.
	const base = lc.split('-')[0];
	if (base === 'es') return 'es';      // es-419, es-ES, es-* all map to es
	if (base === 'pt') return 'pt-BR';   // pt, pt-PT, pt-BR all map to pt-BR
	const baseMatch = SUPPORTED_LOCALES.find(l => l.toLowerCase() === base);
	if (baseMatch) return baseMatch;

	return 'en';
}

// Interpolate {name} placeholders from vars. Uses a function-replace so a value containing
// '$' (e.g. a dollar amount) never triggers String.replace's $-pattern behavior.
function interpolate(str, vars) {
	if (!vars) return str;
	return str.replace(/\{(\w+)\}/g, (_, k) => (vars[k] !== undefined && vars[k] !== null ? String(vars[k]) : ''));
}

// Translate a key for an explicit locale. Falls back: locale table -> en table -> the key itself.
// Used directly by the popup and background (which pass a stored locale).
export function translate(locale, key, vars) {
	const loc = normalizeLocale(locale);
	const table = MESSAGES[loc] || MESSAGES.en;
	let str = table[key];
	if (str === undefined) str = MESSAGES.en[key];
	if (str === undefined) str = key;
	return interpolate(str, vars);
}

// Detect the active locale from the page's lang attribute. Returns 'en' in DOM-less contexts.
export function detectLocale() {
	try {
		return normalizeLocale(document.documentElement.lang);
	} catch (e) {
		return 'en';
	}
}

// The active locale is pinned via setLocaleOverride() at boot (from the account profile in
// content scripts, from stored lastLang in the popup). detectLocale() is only a pre-boot
// fallback for the brief window before the override is set.
let _localeOverride = null;
export function setLocaleOverride(locale) {
	_localeOverride = locale ? normalizeLocale(locale) : null;
}

function currentLocale() {
	return _localeOverride !== null ? _localeOverride : detectLocale();
}

// Primary UI translation entry point.
export function localize(key, vars) {
	return translate(currentLocale(), key, vars);
}

// BCP-47 tag for Intl APIs — same locale as the translated text.
export function localeForIntl() {
	return currentLocale();
}

// Locale-aware integer/thousands formatting (replaces bare Number.toLocaleString()).
export function fmtNum(n) {
	try {
		return Number(n).toLocaleString(localeForIntl());
	} catch (e) {
		return Number(n).toLocaleString();
	}
}
